import React, { useEffect, useState } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { stakingApi, tokensApi } from '../services/api';

const Staking = () => {
  const [searchParams] = useSearchParams();
  const tokenIdParam = searchParams.get('token');

  const [stakingList, setStakingList] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showNewStakingForm, setShowNewStakingForm] = useState(!!tokenIdParam);

  // Для формы нового стейкинга
  const [tokens, setTokens] = useState([]);
  const [tokensLoading, setTokensLoading] = useState(false);
  const [selectedToken, setSelectedToken] = useState(tokenIdParam || '');
  const [amount, setAmount] = useState('');
  const [selectedNetwork, setSelectedNetwork] = useState('');
  const [selectedWallet, setSelectedWallet] = useState('');
  const [destinationAddress, setDestinationAddress] = useState('');
  const [networks, setNetworks] = useState([]);
  const [wallets, setWallets] = useState([]);
  const [formError, setFormError] = useState('');
  const [formSuccess, setFormSuccess] = useState('');
  const [formLoading, setFormLoading] = useState(false);
  const [unstakeLoading, setUnstakeLoading] = useState(false);
  const [unstakeSuccess, setUnstakeSuccess] = useState('');

  // Получение списка стейкинга
  const fetchStakingList = async () => {
    try {
      setLoading(true);
      const response = await stakingApi.getStakingList();
      console.log('Fetched staking list:', response.data);
      setStakingList(response.data);
      setError('');
    } catch (error) {
      console.error('Ошибка при получении списка стейкинга:', error);
      setError('Не удалось загрузить список стейкинга');
    } finally {
      setLoading(false);
    }
  };

  // Загружаем список стейкинга при монтировании компонента
  useEffect(() => {
    fetchStakingList();
  }, []);

  // Получение списка доступных сетей
  useEffect(() => {
    const fetchNetworks = async () => {
      try {
        const response = await stakingApi.getNetworks();
        setNetworks(response.data.networks);
      } catch (error) {
        console.error('Ошибка при получении списка сетей:', error);
        setFormError('Не удалось загрузить список доступных сетей');
      }
    };

    fetchNetworks();
  }, []);

  // Обновление списка доступных кошельков при выборе сети
  useEffect(() => {
    if (selectedNetwork) {
      const network = networks.find(n => n.id === selectedNetwork);
      if (network) {
        setWallets(network.wallets);
        setSelectedWallet(''); // Сбрасываем выбранный кошелек
      }
    } else {
      setWallets([]);
    }
  }, [selectedNetwork, networks]);

  // Получение списка доступных токенов для стейкинга
  useEffect(() => {
    if (showNewStakingForm) {
      const fetchAvailableTokens = async () => {
        try {
          setTokensLoading(true);
          const response = await tokensApi.getAllTokens();
          // Фильтруем только токены, доступные для стейкинга
          const availableTokens = response.data.filter(token => token.staking_available);
          setTokens(availableTokens);
        } catch (error) {
          console.error('Ошибка при получении токенов:', error);
          setFormError('Не удалось загрузить список доступных токенов');
        } finally {
          setTokensLoading(false);
        }
      };

      fetchAvailableTokens();
    }
  }, [showNewStakingForm]);

  // Обработчик отправки формы стейкинга
  const handleStakingSubmit = async (e) => {
    e.preventDefault();

    if (!selectedToken || !amount || amount <= 0 || !selectedNetwork || !selectedWallet || !destinationAddress) {
      setFormError('Пожалуйста, заполните все поля корректно');
      return;
    }

    try {
      setFormError('');
      setFormLoading(true);

      await stakingApi.stakeTokens({
        token_id: parseInt(selectedToken),
        amount: parseFloat(amount),
        network: selectedNetwork,
        destination_address: destinationAddress
      });

      setFormSuccess('Стейкинг успешно создан!');

      // Немедленно обновляем список стейкинга
      await fetchStakingList();

      // Сбрасываем форму через 2 секунды
      setTimeout(() => {
        setShowNewStakingForm(false);
        setSelectedToken('');
        setAmount('');
        setSelectedNetwork('');
        setSelectedWallet('');
        setDestinationAddress('');
        setFormSuccess('');
      }, 2000);

    } catch (error) {
      console.error('Ошибка при создании стейкинга:', error);
      setFormError(error.response?.data?.detail || 'Ошибка при создании стейкинга');
    } finally {
      setFormLoading(false);
    }
  };

  // Обработчик запроса на анстейкинг
  const handleUnstake = async (stakingId) => {
    if (unstakeLoading) return;

    try {
      setUnstakeLoading(true);

      await stakingApi.requestUnstake(stakingId);

      setUnstakeSuccess(`Запрос на анстейкинг принят. Процесс займет примерно 30 секунд`);

      // Обновляем список стейкинга через 1 секунду
      setTimeout(() => {
        fetchStakingList();
      }, 1000);

      // Скрываем сообщение об успехе через 5 секунд
      setTimeout(() => {
        setUnstakeSuccess('');
      }, 5000);

    } catch (error) {
      console.error('Ошибка при запросе на анстейкинг:', error);
      setError(error.response?.data?.detail || 'Ошибка при запросе на анстейкинг');
    } finally {
      setUnstakeLoading(false);
    }
  };

  // Форматирование даты
  const formatDate = (dateString) => {
    if (!dateString) return 'Н/Д';
    const date = new Date(dateString);
    return date.toLocaleDateString('ru-RU');
  };

  // Получение имени токена по ID
  const getTokenSymbol = (tokenId) => {
    const token = tokens.find(t => t.token_id === tokenId);
    return token ? token.token_symbol : `Токен #${tokenId}`;
  };

  // Получение статуса стейкинга в читаемом виде
  const getStatusText = (status) => {
    switch (status) {
      case 'active': return 'Активен';
      case 'unstaking': return 'Анстейкинг (в процессе)';
      case 'completed': return 'Завершен';
      default: return status;
    }
  };

  return (
    <div className="container">
      <h2>Стейкинг</h2>

      {error && <div className="alert alert-danger">{error}</div>}
      {unstakeSuccess && <div className="alert alert-success">{unstakeSuccess}</div>}

      <div className="card">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
          <h3 style={{ margin: 0 }}>Ваши стейкинги</h3>

          <button
            className="btn"
            onClick={() => setShowNewStakingForm(!showNewStakingForm)}
          >
            {showNewStakingForm ? 'Отменить' : 'Новый стейкинг'}
          </button>
        </div>

        {/* Форма нового стейкинга */}
        {showNewStakingForm && (
          <div className="card" style={{ marginBottom: '20px' }}>
            <h4>Создать новый стейкинг</h4>

            {formError && <div className="alert alert-danger">{formError}</div>}
            {formSuccess && <div className="alert alert-success">{formSuccess}</div>}

            <form onSubmit={handleStakingSubmit}>
              {/* Выбор сети */}
              <div className="form-group">
                <label htmlFor="network" className="form-label">
                  Сеть
                </label>
                <select
                  id="network"
                  className="form-control"
                  value={selectedNetwork}
                  onChange={(e) => setSelectedNetwork(e.target.value)}
                  disabled={formLoading}
                  required
                >
                  <option value="">Выберите сеть</option>
                  {networks.map(network => (
                    <option key={network.id} value={network.id}>
                      {network.name}
                    </option>
                  ))}
                </select>
              </div>

              {/* Выбор кошелька */}
              {selectedNetwork && (
                <div className="form-group">
                  <label htmlFor="wallet" className="form-label">
                    Кошелек
                  </label>
                  <select
                    id="wallet"
                    className="form-control"
                    value={selectedWallet}
                    onChange={(e) => setSelectedWallet(e.target.value)}
                    disabled={formLoading}
                    required
                  >
                    <option value="">Выберите кошелек</option>
                    {wallets.map(wallet => (
                      <option key={wallet} value={wallet}>
                        {wallet}
                      </option>
                    ))}
                  </select>
                </div>
              )}

              {/* Адрес кошелька */}
              {selectedWallet && (
                <div className="form-group">
                  <label htmlFor="destinationAddress" className="form-label">
                    Адрес кошелька
                  </label>
                  <input
                    type="text"
                    id="destinationAddress"
                    className="form-control"
                    value={destinationAddress}
                    onChange={(e) => setDestinationAddress(e.target.value)}
                    placeholder={`Введите адрес ${selectedWallet}`}
                    disabled={formLoading}
                    required
                  />
                </div>
              )}

              {/* Выбор токена */}
              {selectedWallet && (
                <div className="form-group">
                  <label htmlFor="token" className="form-label">
                    Токен
                  </label>
                  {tokensLoading ? (
                    <p>Загрузка доступных токенов...</p>
                  ) : (
                    <select
                      id="token"
                      className="form-control"
                      value={selectedToken}
                      onChange={(e) => setSelectedToken(e.target.value)}
                      disabled={formLoading}
                      required
                    >
                      <option value="">Выберите токен</option>
                      {tokens.map(token => (
                        <option key={token.token_id} value={token.token_id}>
                          {token.token_symbol} ({token.token_name})
                        </option>
                      ))}
                    </select>
                  )}
                </div>
              )}

              {/* Количество */}
              {selectedToken && (
                <div className="form-group">
                  <label htmlFor="amount" className="form-label">
                    Количество
                  </label>
                  <input
                    type="number"
                    id="amount"
                    className="form-control"
                    value={amount}
                    onChange={(e) => setAmount(e.target.value)}
                    placeholder="Введите количество токенов"
                    min="0.000001"
                    step="0.000001"
                    disabled={formLoading}
                    required
                  />
                </div>
              )}

              <button
                type="submit"
                className="btn"
                disabled={formLoading || !selectedToken || !amount || !selectedNetwork || !selectedWallet || !destinationAddress}
              >
                {formLoading ? 'Создание стейкинга...' : 'Создать стейкинг'}
              </button>
            </form>
          </div>
        )}

        {/* Список стейкингов */}
        {loading ? (
          <p>Загрузка данных стейкинга...</p>
        ) : stakingList.length > 0 ? (
          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr>
                  <th style={{ textAlign: 'left', padding: '10px', borderBottom: '1px solid #ddd' }}>ID</th>
                  <th style={{ textAlign: 'left', padding: '10px', borderBottom: '1px solid #ddd' }}>Токен</th>
                  <th style={{ textAlign: 'right', padding: '10px', borderBottom: '1px solid #ddd' }}>Количество</th>
                  <th style={{ textAlign: 'center', padding: '10px', borderBottom: '1px solid #ddd' }}>Сеть</th>
                  <th style={{ textAlign: 'center', padding: '10px', borderBottom: '1px solid #ddd' }}>Дата начала</th>
                  <th style={{ textAlign: 'center', padding: '10px', borderBottom: '1px solid #ddd' }}>Статус</th>
                  <th style={{ textAlign: 'center', padding: '10px', borderBottom: '1px solid #ddd' }}>Действия</th>
                </tr>
              </thead>
              <tbody>
                {stakingList.map((staking) => (
                  <tr key={staking.staking_id}>
                    <td style={{ textAlign: 'left', padding: '10px', borderBottom: '1px solid #ddd' }}>
                      <Link to={`/staking/${staking.staking_id}`}>{staking.staking_id}</Link>
                    </td>
                    <td style={{ textAlign: 'left', padding: '10px', borderBottom: '1px solid #ddd' }}>
                      {tokens.length > 0 ? getTokenSymbol(staking.token_id) : `Токен #${staking.token_id}`}
                    </td>
                    <td style={{ textAlign: 'right', padding: '10px', borderBottom: '1px solid #ddd' }}>
                      {staking.amount}
                    </td>
                    <td style={{ textAlign: 'center', padding: '10px', borderBottom: '1px solid #ddd' }}>
                      {staking.network}
                    </td>
                    <td style={{ textAlign: 'center', padding: '10px', borderBottom: '1px solid #ddd' }}>
                      {formatDate(staking.staked_at)}
                    </td>
                    <td style={{ textAlign: 'center', padding: '10px', borderBottom: '1px solid #ddd' }}>
                      {getStatusText(staking.staking_status)}
                    </td>
                    <td style={{ textAlign: 'center', padding: '10px', borderBottom: '1px solid #ddd' }}>
                      {staking.staking_status === 'active' && (
                        <button
                          className="btn btn-sm"
                          onClick={() => handleUnstake(staking.staking_id)}
                          disabled={unstakeLoading}
                        >
                          {unstakeLoading ? 'Обработка...' : 'Анстейкинг'}
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <p>У вас пока нет активных стейкингов</p>
        )}
      </div>
    </div>
  );
};

export default Staking;
